var e=JSON.parse(`[{"id":"L8_1","type":"dialog","speaker":"SQUAD_MAIN_NPC_CAP","text":{"KOREA":"이 빌어먹을 자식들! 이거나 먹어라!","JPN":"このバケモノども！　これでも食らえ！","ENG":"You bastards! Come get some!","TWN":"你們這些該死的傢伙！吃我一招！"},"stage":{"bg":"CORRIDOR_04","bgm":"BATTLE_BOSS_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SQUAD_MAIN_NPC_CAP","face":"UNIT_IDLE"},"R":{"char_id":"SQUAD_MAIN_NPC_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_COMBAT_ALL_GUN_RELOAD_SMALL"},{"id":"L11_1","type":"dialog","speaker":"SQUAD_MAIN_NPC_CAP","text":{"KOREA":"제기랄! 끝도 없이 몰려오는군!","JPN":"くっそ！　きりがない！","ENG":"Damn it! They just keep coming!","TWN":"可惡！沒完沒了地湧過來！"},"stage":{"bg":"CORRIDOR_04","bgm":"BATTLE_BOSS_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SQUAD_MAIN_NPC_CAP","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L12_1","type":"dialog","speaker":"SQUAD_MAIN_NPC_CAP","text":{"KOREA":"소령님! 지시하신 아티팩트 보관 구역에 거의 도착했습니다!","JPN":"少佐！　もうすぐ指示されたアーティファクトの保管区域に着きます！","ENG":"Major! We're almost at the Artifact storage zone you specified!","TWN":"少校！我們快到你指示的神器保管區了！"},"stage":{"bg":"CORRIDOR_04","bgm":"BATTLE_BOSS_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SQUAD_MAIN_NPC_CAP","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SQUAD_MAIN_NPC_CAP","text":{"KOREA":"여긴 저희가 맡을 테니, 먼저 가십시오!","JPN":"ここは我々が引き受けますので、先に行ってください！","ENG":"We'll hold the line here! Go on ahead!","TWN":"這裡就交給我們吧，你先走！"},"stage":{"bg":"CORRIDOR_04","bgm":"BATTLE_BOSS_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SQUAD_MAIN_NPC_CAP","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"……그럼, 부탁드리겠습니다.","JPN":"……では、お願いします。","ENG":"...Then I'll leave it to you.","TWN":"……那就拜託你了。"},"stage":{"bg":"CORRIDOR_04","bgm":"BATTLE_BOSS_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"SQUAD_MAIN_NPC_CAP","text":{"KOREA":"총알 남은 거 있으면, 전부 때려 박아!","JPN":"残ってる弾があれば、全部撃ち込め！","ENG":"Unload every last round you've got!","TWN":"如果還有子彈的話，全都給我打出去！"},"stage":{"bg":"CORRIDOR_04","bgm":"BATTLE_BOSS_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SQUAD_MAIN_NPC_CAP","face":"UNIT_IDLE"},"R":{"char_id":"SQUAD_MAIN_NPC_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_COMBAT_ALL_GUN_RELOAD_SMALL"},{"id":"L24_1","type":"dialog","speaker":"SQUAD_MAIN_NPC_CAP","text":{"KOREA":"카운터분들을 목적지까지 에스코트하는 게 우리의 역할이다!","JPN":"カウンターの方々を目的地までエスコートするのが我々の役目だ！","ENG":"Our job is to escort the Counters to their destination!","TWN":"護送制裁者們到達目的地是我們的職責！"},"stage":{"bg":"CORRIDOR_04","bgm":"BATTLE_BOSS_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SQUAD_MAIN_NPC_CAP","face":"UNIT_IDLE"},"R":{"char_id":"SQUAD_MAIN_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"SQUAD_MAIN_NPC_CAP","text":{"KOREA":"목숨을 걸어서라도, 끝까지 이 자리를 사수하는 거다!","JPN":"命に代えてでも、最後までこの場を守り抜け！","ENG":"No matter what it takes, we hold this position to the end!","TWN":"即使拼上性命，也要守住這個位置！"},"stage":{"bg":"CORRIDOR_04","bgm":"BATTLE_BOSS_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SQUAD_MAIN_NPC_CAP","face":"UNIT_IDLE"},"R":{"char_id":"SQUAD_MAIN_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"보관 구역에 도착했어! 다들 서둘러!","JPN":"保管区域に着いたわ！　みんな急いで！","ENG":"We've reached the storage zone! Move it, everyone!","TWN":"已經到達保管區！大家快點行動！"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"리프노드! 이 구역의 격벽을 전부 차단해! 당장……!","JPN":"リーフノード！　この区域の隔壁を全て遮断しなさい！　今すぐ……！","ENG":"Leaf Node! Seal off all bulwarks in this area! Now...!","TWN":"節點！封鎖這個區域的所有隔離牆！快……！"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"하아… 하아……!","JPN":"はあ……はあ……！","ENG":"*Huff...* *Huff…!*","TWN":"哈啊……哈啊……！"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L35_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"어떻게든 막아냈나? 카일, 신참! 두 사람 다 괜찮아?","JPN":"なんとか防いだ？　カイル、新入り！　2人とも無事なの？","ENG":"Did we hold the line? Kyle! Rookie! Are you both okay?","TWN":"總算是擋住了嗎？凱爾，新人！你們兩個都沒事吧？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"AMY_FREEDOM_NULL_NULL","text":{"KOREA":"이야~! 나이스 타이밍이야, 해커!","JPN":"いや～！　ナイスタイミングだったよ、ハッカーさん！","ENG":"Whoa! Perfect timing, hacker!","TWN":"哇～ 好時機啊，駭客！"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AMY_FREEDOM_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L39_1","type":"dialog","speaker":"AMY_FREEDOM_NULL_NULL","text":{"KOREA":"조금만 더 빨리 닫았으면, 나란히 와플이 되어버릴 뻔했다고?","JPN":"もうちょっと閉めるのが早かったら、2人揃ってワッフルになるところだったよ！","ENG":"A second later and we'd have ended up flattened like waffles, side by side!","TWN":"再快一點關上的話，我們就要一起變成夾心餅了？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AMY_FREEDOM_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L40_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"시끄러워, 신참. 방금 건, 나 아니었으면 우리 셋 다 죽은 목숨이었거든?","JPN":"黙りなさい、新入り。今のはアタシじゃなかったら3人とも終わってたわ。","ENG":"Quiet, rookie. Without me, we'd all be dead meat right now.","TWN":"閉嘴，新人。剛才那一下，要不是我，我們三個都得死。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"AMY_FREEDOM_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L41_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"뭐, 저 격벽이 얼마나 버텨줄지는 모르겠지만…….","JPN":"まあ、あの隔壁がいつまで耐えてくれるかが問題だけど……","ENG":"Not that I know how long that bulwark's actually going to hold...","TWN":"嗯，不知道那道隔牆能撐多久……"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AMY_FREEDOM_NULL_NULL","face":"UNIT_PRIDE"}}},"sfx":"FX_COMBAT_MONSTER_BEAST_VOICE_30"},{"id":"L42_1","type":"dialog","speaker":"AMY_FREEDOM_NULL_NULL","text":{"KOREA":"아하하. 와플보다는 통조림 신세가 좀 나은가?","JPN":"あはは、ワッフルよりは缶詰の方がマシかな？","ENG":"Ahaha. I guess being canned is better than being waffle-pressed, huh?","TWN":"啊哈哈，比起夾心餅，罐頭的待遇是不是好一點？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AMY_FREEDOM_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L44_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"어쨌든 서두르죠.","JPN":"とにかく急ぎましょう。","ENG":"Anyway, let's move.","TWN":"總之，快點吧。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L45_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"격벽이 침식체를 막아주는 동안, 아티팩트를 회수해야 합니다.","JPN":"隔壁が侵食体を防いでくれているうちに、アーティファクトを回収する必要があります。","ENG":"We need to retrieve the Artifact while the bulwark's still holding back C.O.s.","TWN":"在隔牆阻擋侵蝕體的同時，必須回收神器。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>시스템 권한을 확인 중.</color>","JPN":"<color=#ffd34c>システム権限を確認中。</color>","ENG":"<color=#ffd34c>Verifying system authorization.</color>","TWN":"<color=#ffd34c>正在確認系統許可權。</color>"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_BEEP4"},{"id":"L1_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>확인 완료. 불멸체 시스템의 테스트 기동을 종료합니다.</color>","JPN":"<color=#ffd34c>確認完了。不滅体システムのテスト起動を終了します。</color>","ENG":"<color=#ffd34c>Authorization confirmed. Shutting down Immortal System test mode.</color>","TWN":"<color=#ffd34c>確認完畢，結束不滅者系統的測試啟動。</color>"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_BEEP4"},{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>메인 프레임에서 코어를 분리합니다.</color>","JPN":"<color=#ffd34c>メインフレームからコアを切り離します。</color>","ENG":"<color=#ffd34c>Detaching core from mainframe.</color>","TWN":"<color=#ffd34c>從主框架中分離核心。</color>"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_BEEP4"},{"id":"L6_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"……이제 알겠군요.","JPN":"……やっとわかりました。","ENG":"...Now it makes sense.","TWN":"……原來如此，我現在知道了。"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L7_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"아무래도 이 불멸체 코어는 물체를 분해하거나, 재구성하는 장치인 것 같습니다.","JPN":"どうやらこの不滅体コアは、物体を分解したり再構成する装置のようです。","ENG":"It seems this Immortal System Core is a device capable of breaking down and reconstructing matter.","TWN":"看來這個不滅者核心是用來分解或重組物體的裝置。"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"침식체에게 파괴된 시설의 비상 동력원이 멀쩡했던 이유도 이 불멸체 코어 때문이었어요.","JPN":"侵食体に破壊された施設の非常動力源が無事だったのも、この不滅体コアがあったためです。","ENG":"That also explains why the emergency power was still functioning despite the damage caused by C.O.s.","TWN":"被侵蝕體破壞的設施緊急動力源完好無損，也是因為這個不滅者核心。"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"이곳의 시스템을 유지하기 위해, 코어가 파괴된 동력 설비를 재생시키고 있던 거죠.","JPN":"ここのシステムを維持するために、コアが破壊された動力設備を再生していたんでしょう。","ENG":"The Core was actively restoring the damaged power facility to keep the facility operational.","TWN":"為了維持這裡的系統，正在修復核心被破壞的動力設備。"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"잠깐, 뭔가 이상하잖아?","JPN":"ちょっと待って、それっておかしいじゃない。","ENG":"Wait a second, doesn't this seem off?","TWN":"等一下，感覺有點不對勁吧？"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L13_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"시설에 생존자가 아무도 없는데, 시스템이 혼자서 뭘 테스트하고 있었다는 건데?","JPN":"施設には生存者もいないのに、システムだけで何のテストをしてたっていうの。","ENG":"There's no one alive in this facility, so what exactly was the system testing by itself?","TWN":"設施裡沒有倖存者，系統一個人在測試什麼呢？"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"……테스트 샘플이 사라졌어요.","JPN":"……テストサンプルが消えています。","ENG":"...The test sample is gone.","TWN":"……測試樣本消失了。"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"이래서는 시스템이 무엇을 복제하려 했는지 알 수가 없군요.","JPN":"これではシステムが何をコピーしようとしていたのか、知る術がありませんね。","ENG":"Without it, there's no way to determine what the system was attempting to duplicate.","TWN":"這樣的話，無法知道系統試圖複製什麼。"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"그 말은… 누군가가 원본 샘플을 가져갔다는 뜻이야?","JPN":"それってつまり……誰かが元のサンプルを持ってったってこと？","ENG":"So you're saying... someone took the original sample?","TWN":"那就是說……有人拿走了原始樣本？"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L17_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"도대체 관리국이랑 합중국은 이런 곳에 짱 박혀서 뭘 연구하고 있었던 거야?","JPN":"いったい管理局と合衆国はこんなとこに引きこもって、何の研究をしていたの？","ENG":"Just what were the Administration and the States hiding away in a place like this?","TWN":"到底管理局和合眾國在這種地方藏著研究什麼呢？"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L18_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L21_1","type":"dialog","speaker":"AMY_FREEDOM_NULL_NULL","text":{"KOREA":"저기요, 소령님~","JPN":"もしもーし、少佐～？","ENG":"Excuse me, Major?","TWN":"喂，少校～"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_FREEDOM_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"AMY_FREEDOM_NULL_NULL","text":{"KOREA":"지금 한가롭게 공상 과학 토론이나 벌이고 있을 때가 아닌 것 같은데요~?","JPN":"今は呑気に空想科学の討論なんてしている場合じゃないと思うんだけど～？","ENG":"Now's probably not the best time for a sci-fi debate, don't you think?","TWN":"現在好像不是悠閒地討論科幻的時候吧？"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_FREEDOM_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"옳습니다. 어찌됐든 최우선 목표였던 불멸체 코어는 확보하였습니다.","JPN":"その通りです。とにかく最優先目標の不滅体コアは確保できました。","ENG":"You're right. In any case, we've secured the Immortal System Core, which was our top priority.","TWN":"沒錯，不管怎樣，最優先目標不滅者核心已經到手了。"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"이제 탈출 루트를 확보한 뒤에…… ","JPN":"これから脱出ルートを確保し……","ENG":"Once we secure an escape route...","TWN":"現在確保逃脫路線之後……"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"흠!?","JPN":"っ！？","ENG":"Hmm?!","TWN":"嗯？！"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L28_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"실비아 씨!! 당장 거기서 피하세요……!!","JPN":"シルビアさん！！　今すぐそこから離れて……！！","ENG":"Sylvia! Get out of there, now...!","TWN":"希爾維亞！！快從那裡躲開……！！"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"꺄, 꺄아악……!!","JPN":"き、きゃああっ……！！","ENG":"Kyaaaah...!","TWN":"啊，啊啊啊……！！"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_COMBAT_ALL_MOVEMENT_04"},{"id":"L32_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"커흑……!!","JPN":"がはっ……！！","ENG":"Kuh...!","TWN":"唔……！！"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_BIG_02"},{"id":"L35_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"야, 카일! 너 괜찮아?","JPN":"カイル！　大丈夫！？","ENG":"Kyle! Are you okay?","TWN":"喂，凱爾！你沒事吧？"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L36_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"크윽, 이 정도는… 괜찮습니다…….","JPN":"くっ、これくらい……大したことありません……","ENG":"Urgh, I can manage... it's nothing serious...","TWN":"咳，這點傷……沒事……"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L37_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"하지만…….","JPN":"しかし……","ENG":"But...","TWN":"但是……"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L41_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"말도 안 돼……!","JPN":"嘘でしょ……！","ENG":"No way...!","TWN":"這不可能……！"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"저건 4종 침식체잖아…? 설마, 그 두리안 버터맨이 실패한 거야……?","JPN":"あれって第4種侵食体じゃない……？　まさか、あのドリアンバターマンが失敗したの……？","ENG":"That's a Category 4 C.O.! Don't tell me that sleazeball failed..?","TWN":"那是4類侵蝕體……？難道，那個黃毛失敗了……？"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"아니요. 대령님이 그렇게 쉽게 당할 리 없습니다.","JPN":"いいえ、大佐がそんな簡単にやられるはずありません。","ENG":"No. Colonel wouldn't go down that easily.","TWN":"不，上校不可能這麼容易就被打敗。"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L46_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"저건 사전에 보고 받았던 4종 침식체가 아니에요. 다른 개체입니다.","JPN":"あれは事前に報告を受けている第4種侵食体ではありません。違う個体です。","ENG":"That's not the Category 4 C.O. we were briefed on. It's a different one.","TWN":"那不是事前報告的4類侵蝕體，是其他個體。"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"그럼, 처음부터 이 시설을 점거하고 있던 4종 침식체가 하나가 아니었다고……?","JPN":"じゃあ、何？　この施設を占拠していた第4種侵食体は、最初から1体じゃなかった……？","ENG":"Then there was more than one Category 4 C.O. occupying this facility from the start...?","TWN":"那麼，從一開始就佔據這個設施的4類侵蝕體不止一個……？"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L48_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"큭! 두 번째! 옵니다! 어서 피하세요……!!","JPN":"くっ！　また来ます！　早く避けて……！！","ENG":"Urgh! The second one's coming! Get out of the way, now...!","TWN":"呃！第二波！來了！快躲開……！！"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_HATE"}}},"sfx":"FX_COMBAT_MONSTER_BEAST_VOICE_41"},{"id":"L1_1","type":"dialog","speaker":"AMY_FREEDOM_NULL_NULL","text":{"KOREA":"나 참, 사이좋은 건 알겠는데, 언제까지 둘이 껴안고 있을 거야?","JPN":"まったく、仲良いのはわかるけど、いつまで抱き合っているつもり？","ENG":"Wow, I get that you two are close, but is now really the time for cuddling?","TWN":"哎呀，我知道你們關係好，但你們要抱到什麼時候啊？"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_FREEDOM_NULL_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_COMBAT_ALL_MOVEMENT_02"},{"id":"L2_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"에이미 스트릭랜드……?","JPN":"エイミー・ストリクランド……？","ENG":"Amy Strickland...?","TWN":"艾米·斯特里克蘭……？"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"당신… 방금 4종 침식체의 공격을……?","JPN":"あなた……今第4種侵食体の攻撃を……？","ENG":"Did you... just deflect an attack of a Category 4 C.O.?","TWN":"你……剛剛遭受了4類侵蝕體的攻擊……？"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"AMY_FREEDOM_NULL_NULL","text":{"KOREA":"쳇! 뭘 그렇게 얼빠진 표정들 하고 있어!","JPN":"ちっ！　2人して何まぬけな顔してんの！","ENG":"Tch! Quit staring like you've seen a ghost!","TWN":"嘖！幹嘛露出那種失魂落魄的表情！"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_FREEDOM_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"AMY_FREEDOM_NULL_NULL","text":{"KOREA":"처음부터 우리에게 선택지 같은 건 없었다고! 4종이든 뭐든 싸울 수밖에 없잖아!","JPN":"最初から私たちに選択肢なんかなかった！　第4種だろうと何だろうと、戦うしかないじゃん！","ENG":"We never had a choice to begin with! Category 4 or not, we have to fight!","TWN":"從一開始我們就沒有選擇的餘地！不管是四類還是其他，我們只能戰鬥！"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_FREEDOM_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"AMY_FREEDOM_NULL_NULL","text":{"KOREA":"아! 진짜! 중요한 작전이라면서?","JPN":"ああ！　もう！　大事な作戦なんでしょ？","ENG":"Come on! Didn't you say this was an important operation?","TWN":"啊！真是的！不是說是重要的作戰嗎？"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_FREEDOM_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L10_1","type":"dialog","speaker":"AMY_FREEDOM_NULL_NULL","text":{"KOREA":"거슬리니까 도망칠 거면, 빨랑 도망치든가! 시간 정도는 벌어줄 테니까!","JPN":"邪魔だから逃げるならさっさと逃げてくんない？　時間稼ぎくらいはしてあげるからさ！","ENG":"If you're gonna run, then hurry up and go! I'll buy you some time, so get moving!","TWN":"礙眼的傢伙，要逃就快點逃吧！我會幫你爭取點時間的！"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_FREEDOM_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"……아니요, 그 반대입니다.","JPN":"……いいえ、その逆です。","ENG":"...No. It's the other way around.","TWN":"……不，不是那樣的。"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"AMY_FREEDOM_NULL_NULL","text":{"KOREA":"이건, 불멸체 코어……?","JPN":"これは、不滅体コア……？","ENG":"This is... the Immortal System Core...?","TWN":"這是，不滅者核心……？"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_FREEDOM_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_COMBAT_ALL_MOVEMENT_02"},{"id":"L16_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"가세요, 이곳 4종 침식체는 저희가 맡겠습니다.","JPN":"行ってください。ここの第4種侵食体は僕たちが引き受けます。","ENG":"Leave this to us. We'll deal with the Category 4 C.O.","TWN":"快走，這裡的4類侵蝕體交給我們。"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"냉정하게 봤을 때, 여기서 가장 작전 성공률이 높은 건 당신이니까요, 스트릭랜드.","JPN":"冷静に考えて、この中で最も作戦成功率が高いのはあなたです、ストリクランド。","ENG":"If we're being honest, you're the one with the highest chance of completing the operation, Strickland.","TWN":"冷靜來看，目前作戰成功率最高的就是你，斯特里克蘭。"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"AMY_FREEDOM_NULL_NULL","text":{"KOREA":"……쳇.","JPN":"……ちっ。","ENG":"...Tch.","TWN":"……嘖。"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_FREEDOM_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"AMY_FREEDOM_NULL_NULL","text":{"KOREA":"이런 역할은 꿈자리 사나워져서 딱 질색인데 말이지.","JPN":"こういう役回り、夢見が悪くなるから大っ嫌いなんだけど。","ENG":"I hate taking on roles that leave me with bad dreams, though.","TWN":"這種角色會讓我做噩夢，真是討厭。"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_FREEDOM_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"AMY_FREEDOM_NULL_NULL","text":{"KOREA":"나중에 죽어서 원망하기 없기다?","JPN":"死んでから恨むのナシだよ？","ENG":"So if you die, don't go blaming me from the afterlife, got it?","TWN":"以後死了可別怨我？"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_FREEDOM_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"이쪽입니다! 어서요!","JPN":"こっちです！　急いで！","ENG":"This way! Hurry!","TWN":"這邊！快點！"},"stage":{"bg":"WAREHOUSE_03","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"헉, 허억! 알아! 안다고……!","JPN":"はっ、はぁ！　わかってる！　わかってるって……！","ENG":"*Pant* I got it, okay?!","TWN":"咳，咳！我知道！我知道的……！"},"stage":{"bg":"WAREHOUSE_03","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L33_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"나도 최선을 다해 뛰고 있단 말이야……!","JPN":"これでも一生懸命走ってるのよ……！","ENG":"I'm running as fast as I can...!","TWN":"我也在全力奔跑啊……！"},"stage":{"bg":"WAREHOUSE_03","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L37_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"이건 정전……?","JPN":"これは、停電……？","ENG":"A blackout...?","TWN":"這是停電……？"},"stage":{"bg":"WAREHOUSE_03","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L38_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"아마 불멸체 코어가 사라져서, 시설의 비상 동력원이 끊어졌겠지.","JPN":"おそらく不滅体コアが消えたことで、施設の非常動力源が切れたんでしょうね。","ENG":"Probably because the Immortal System Core was removed. The emergency power must've shut down.","TWN":"大概是不滅者核心消失了，設施的應急電源被切斷了吧。"},"stage":{"bg":"WAREHOUSE_03","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"이제부터는 나도 시설의 설비를 컨트롤할 수 없어.","JPN":"ここからはもうアタシも施設の設備をコントロールできない。","ENG":"From here on out, I can't control the facility systems anymore.","TWN":"從現在開始我也無法控制設施的設備了。"},"stage":{"bg":"WAREHOUSE_03","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L42_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"스트릭랜드 씨가 무사히 탈출했기를 비는 수밖에 없군요.","JPN":"ストリクランドさんが無事脱出できていることを願うしかありませんね。","ENG":"All we can do now is hope Strickland made it out safely.","TWN":"只能祈禱斯特里克蘭能平安逃脫了。"},"stage":{"bg":"WAREHOUSE_03","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L43_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"그 전에… 우리 걱정을 먼저 하는 게 어떨까?","JPN":"その前に……まずは自分たちの心配からしたらどう？","ENG":"Before that... maybe we should worry about ourselves first?","TWN":"在那之前……我們還是先擔心一下自己吧？"},"stage":{"bg":"WAREHOUSE_03","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L45_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"WAREHOUSE_03","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_COMBAT_ALL_GUN_RELOAD_SMALL_02"},{"id":"L46_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"실비아 씨, 여기는 제가 맡겠습니다.","JPN":"シルビアさん、ここは僕が引き受けます。","ENG":"Leave this area to me, Sylvia.","TWN":"希爾維亞，這裡交給我吧。"},"stage":{"bg":"WAREHOUSE_03","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"4종 침식체가 나타나면 곧바로 도망치세요.","JPN":"第4種侵食体が現れたら、すぐに逃げてください。","ENG":"If a Category 4 C.O. shows up, you need to run. Immediately.","TWN":"如果出現4類侵蝕體，立刻逃跑。"},"stage":{"bg":"WAREHOUSE_03","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"뭐어? 갑자기 무슨 헛소리야?","JPN":"はあ？　急に何言ってんの？","ENG":"What? What are you talking about all of a sudden?!","TWN":"什麼？你突然胡說什麼？"},"stage":{"bg":"WAREHOUSE_03","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L1_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"아무래도… 저는 여기까지인 것 같거든요…….","JPN":"どうやら……僕はここまでのようです……","ENG":"I think... this is where my road ends...","TWN":"看來我也到此為止了……"},"stage":{"bg":"WAREHOUSE_03","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L2_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"피를 너무 많이 흘렸습니다… 아까부터 시야가 흐릿해서 잘 보이지도 않아요…….","JPN":"血を流しすぎました……先ほどから視界がぼやけて、前もよく見えません……","ENG":"I've lost too much blood... My vision's been blurry for a while now... I can barely see...","TWN":"我流了太多血……從剛才開始視線就變得模糊，看不清東西了……"},"stage":{"bg":"WAREHOUSE_03","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L3_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"잠깐만, 그럼 너 설마 아까 나를 감싸다가……?","JPN":"待って、あんたまさかさっきアタシを庇った時に……？","ENG":"Hold on... Was it because you covered me back there...?","TWN":"等等，那麼你不會是剛才為了保護我……？"},"stage":{"bg":"WAREHOUSE_03","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L4_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"그 신참을 먼저 보낸 것도……?","JPN":"じゃあ、あの新入りを先に行かせたのも……？","ENG":"And sending away the rookie first... That was on purpose, wasn't it?","TWN":"是先派那個新手去的嗎……？"},"stage":{"bg":"WAREHOUSE_03","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"옵니다, 실비아 씨……!","JPN":"来ます、シルビアさん……！","ENG":"Incoming, Sylvia...!","TWN":"來了，希爾維亞……！"},"stage":{"bg":"WAREHOUSE_03","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"실랑이할 시간이 없어요! 뛰세요!","JPN":"揉めている時間はありません！　走って！","ENG":"There's no time to argue, run!","TWN":"我沒時間和你們糾纏！快跑！"},"stage":{"bg":"WAREHOUSE_03","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"카일, 이 멍청이가! 끝까지…… ","JPN":"カイル、このアホ！　最後まで……","ENG":"Kyle, you fool! Even to the very end...","TWN":"凱爾，你這個笨蛋！直到最後……"},"stage":{"bg":"WAREHOUSE_03","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"음!?","JPN":"……えっ？","ENG":"Hmm?","TWN":"嗯？！"},"stage":{"bg":"WAREHOUSE_03","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"어라……?","JPN":"なに……？","ENG":"Huh...?","TWN":"咦……？"},"stage":{"bg":"WAREHOUSE_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SURPRISE"}}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_BIG_02"},{"id":"L19_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"4종 침식체가…. 갑자기……?","JPN":"第4種侵食体が……急に……？","ENG":"The Category 4 C.O. suddenly...!","TWN":"4類侵蝕體……突然……？"},"stage":{"bg":"WAREHOUSE_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"SWAN_SIX_NULL_QM","text":{"KOREA":"괜찮나, 제군들?","JPN":"無事か、諸君。","ENG":"Are you all right, soldiers?","TWN":"諸位，沒事吧？"},"stage":{"bg":"WAREHOUSE_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"당신은……?","JPN":"あなたは……？","ENG":"You are...?","TWN":"你是……？"},"stage":{"bg":"WAREHOUSE_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"JAINA_DELTA_NPC_NULL","text":{"KOREA":"제이나 크로펠 소령, 부사령관님께 귀관들의 구조 및 아티팩트 회수를 명 받았다.","JPN":"ジェイナ・クロペル少佐だ。副司令官より貴官らの救助及びアーティファクト回収の命を受けた。","ENG":"Major Jaina Kropel, by order of the Deputy Commander, I've been dispatched to rescue you and secure the Artifact.","TWN":"少校婕娜·克洛佩爾，受副司令官之命對你們進行救援並回收神器。"},"stage":{"bg":"WAREHOUSE_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAINA_DELTA_NPC_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L27_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"부사령관…? 그 미친 군바리가 우릴 구하라고 했다고?","JPN":"副司令官……？　あのイカレ軍人がアタシたちを助けろって言ったの？","ENG":"Deputy Commander...? That damn GI actually sent someone to save us?","TWN":"副司令官……？那個當兵的瘋子讓你來救我們？"},"stage":{"bg":"WAREHOUSE_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L28_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"하, 하하하…! 살다 살다 그 개자식한테 고마운 건 또 처음이네!","JPN":"は、ははは……！　まさか生きててあのクソ野郎に感謝する日が来るなんて！","ENG":"Hah! Unbelievable... this is the first time I've ever felt thankful to that bastard!","TWN":"哈，哈哈哈…！活了這麼久，還是第一次感謝那個混蛋呢！"},"stage":{"bg":"WAREHOUSE_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L30_1","type":"dialog","speaker":"JAINA_DELTA_NPC_NULL","text":{"KOREA":"크흠! 극적인 상황이긴 하지만, 지휘관에 대한 무례한 언사는 삼가도록.","JPN":"ごほん！　劇的な状況ではあるが、指揮官に対する無礼な言動は慎むように。","ENG":"Ahem! Dramatic or not, let's keep the disrespect toward the Commander to a minimum.","TWN":"咳咳！雖然情況緊急，但請注意不要對指揮官無禮。"},"stage":{"bg":"WAREHOUSE_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAINA_DELTA_NPC_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"JAINA_DELTA_NPC_NULL","text":{"KOREA":"두 사람 모두 다친 곳은 괜찮나? 회수한 불멸체 코어는 어디에 있지?","JPN":"2人とも怪我は大丈夫か？　回収した不滅体コアはどこにある？","ENG":"Are you both all right? Any injuries? And where's the recovered Immortal System Core?","TWN":"你們兩個人受傷的地方還好嗎？回收的不滅者核心在哪裡？"},"stage":{"bg":"WAREHOUSE_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAINA_DELTA_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"야, 카일! 살았어! 이제 살았다고!","JPN":"カイル！　もう大丈夫よ！　生き残ったのよ！","ENG":"Hey, Kyle! We're alive! We actually survived this!","TWN":"喂，凱爾！活下來了！現在真的活下來了！"},"stage":{"bg":"WAREHOUSE_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L35_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"WAREHOUSE_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L37_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"무슨 짓이야, 카일?","JPN":"何してるの、カイル？","ENG":"What are you doing, Kyle?","TWN":"你在幹什麼，凱爾？"},"stage":{"bg":"WAREHOUSE_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"왜 갑자기 소령님께 총을……?","JPN":"何でいきなり少佐に銃なんか……？","ENG":"Why are you pointing your gun at the Major...?","TWN":"為什麼突然對少校開槍……？"},"stage":{"bg":"WAREHOUSE_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"실비아 씨…….","JPN":"シルビアさん……","ENG":"Sylvia...","TWN":"希爾維亞……"},"stage":{"bg":"WAREHOUSE_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"이자가 누구인지는 모르겠지만… 아마도 아군은 아닐 겁니다.","JPN":"この者が誰かは知りませんが……おそらく味方ではありません。","ENG":"I don't know who this person really is... but I'm pretty sure she's not on our side.","TWN":"雖然不知道這傢伙是誰……但她應該不是我方的人。"},"stage":{"bg":"WAREHOUSE_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"뭐라고……?","JPN":"え……？","ENG":"What...?","TWN":"什麼……？"},"stage":{"bg":"WAREHOUSE_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L45_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"4종 침식체가 출몰한 작전 구역에 병력 지원도 없이 혼자 나타난 것…….","JPN":"第4種侵食体が出た作戦区域に、兵力の応援もなしに単身で現れたこと……","ENG":"You showed up alone in an operation zone crawling with Category 4 C.O.s, with no backup whatsoever...","TWN":"在出現4類侵蝕體的作戰區域，沒有任何兵力支援，獨自現身……"},"stage":{"bg":"WAREHOUSE_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"우리가 연구 시설에 도착했을 때, 누군가가 이미 테스트 샘플에 손을 댄 것…….","JPN":"僕たちが研究施設に着いたとき、すでに何者かの手によってテストサンプルが抜かれていたこと……","ENG":"By the time we arrived, someone had already tampered with the test sample...","TWN":"我們到達研究設施時，已經有人動了測試樣本……"},"stage":{"bg":"WAREHOUSE_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"그리고 무엇보다도……","JPN":"そして何より……","ENG":"And most importantly...","TWN":"而且，最重要的是……"},"stage":{"bg":"WAREHOUSE_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"작전 목표인 고등급 아티팩트에 관한 정보는 1급 기밀이었습니다.","JPN":"作戦のターゲットである高ランクアーティファクトに関する情報は第1級の機密事項でした。","ENG":"The target Artifact was classified at the highest security level.","TWN":"作戰目標的高級神器資訊屬於一級機密。"},"stage":{"bg":"WAREHOUSE_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"그런데 당신이 어떻게 불멸체 코어에 관해 알고 있죠?","JPN":"それなのに、どうしてあなたは不滅体コアのことを知っているのですか？","ENG":"So tell me, how did you know about the Immortal System Core?","TWN":"但是你怎麼會知道不滅者核心的事情呢？"},"stage":{"bg":"WAREHOUSE_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"JAINA_DELTA_NPC_NULL","text":{"KOREA":"……후후.","JPN":"……ふふ。","ENG":"...Haha.","TWN":"……呵呵。"},"stage":{"bg":"WAREHOUSE_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAINA_DELTA_NPC_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"JAINA_DELTA_NPC_NULL","text":{"KOREA":"카일 웡 소령. 직감이 꽤 나쁘지 않은 편이로군요.","JPN":"カイル・ウォン少佐。察しがいいのですね。","ENG":"Major Kyle Wong, you've got some impressive intuition.","TWN":"凱爾少校，直覺還不錯嘛。"},"stage":{"bg":"WAREHOUSE_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAINA_DELTA_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"하지만 당신이 모르는 게 있답니다.","JPN":"ですが、あなたが知らないことがあります。","ENG":"Still, there's a piece of the puzzle you're missing.","TWN":"但是有些事情你還不知道。"},"stage":{"bg":"WAREHOUSE_03","bgm":"THEMA_CA_SWAN_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"도미닉 킹 레지날드의 성격 상, 신뢰하는 최측근에게는 테라사이드 프로젝트에 관한 모든 진실을 알려주었을 가능성이 크죠.","JPN":"ドミニーク・キング・レジナルドの性格上、信頼する最側近にはテラサイドプロジェクトに関する全ての真実を伝えている可能性が高い。","ENG":"Given Dominic King Reginald's personality, it's highly likely he shared everything about the Terraside Project with those he trusted most.","TWN":"以多明尼克的性格來看，他很可能會將有關特拉賽德計畫的所有真相告訴他最信任的親信。"},"stage":{"bg":"WAREHOUSE_03","bgm":"THEMA_CA_SWAN_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"따라서 제이나 크로펠이 살아있었다면, 불멸체 코어에 관해 알고 있어도 이상하지 않아요.","JPN":"つまりジェイナ・クロペルが生きていた場合、不滅体コアのことを知っていたとしてもおかしくはありません。","ENG":"So if Jaina Kropel were still alive, it wouldn't be strange for her to know about the Immortal System Core.","TWN":"因此，如果婕娜·克洛佩爾還活著的話，知道不死體核心也不奇怪。"},"stage":{"bg":"WAREHOUSE_03","bgm":"THEMA_CA_SWAN_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"결과적으로, 당신은 그걸 몰랐기 때문에 제 존재를 눈치챌 수 있었겠지만.","JPN":"結果的にそれをわかっていなかったから、あなたは私の存在に気づけたのでしょうけど。","ENG":"But because you lacked that knowledge, you were able to see through me.","TWN":"正因為你不知道，所以才會察覺到我的存在吧。"},"stage":{"bg":"WAREHOUSE_03","bgm":"THEMA_CA_SWAN_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"테라사이드 프로젝트……?","JPN":"テラサイドプロジェクト……？","ENG":"Terraside Project...?","TWN":"特拉賽德計畫……？"},"stage":{"bg":"WAREHOUSE_03","bgm":"THEMA_CA_SWAN_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"하지만 모든 것은 각본대로.","JPN":"ですが、すべては脚本どおりに。","ENG":"But everything according to the script.","TWN":"但是一切都將按照劇本進行。"},"stage":{"bg":"WAREHOUSE_03","bgm":"THEMA_CA_SWAN_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"당신들에게 불멸체 코어가 없는 것을 보니, 아무래도 회수 작전이 성공한 모양이로군요.","JPN":"あなたたちが不滅体コアを持っていないということは、どうやら回収作戦は成功したようですね。","ENG":"I see the Immortal System Core isn't in your possession... so it looks like the recovery mission was a success.","TWN":"你們沒有不滅者核心，看來回收作戰成功了。"},"stage":{"bg":"WAREHOUSE_03","bgm":"THEMA_CA_SWAN_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그렇다면 구태여 제가 개입하지 않아도, 궁지에 몰린 당신들은 천사 강림을 시도할 겁니다.","JPN":"ならばわざわざ私が介入せずとも、窮地に追い込まれたあなたたちは天使の降臨を試みるでしょう。","ENG":"In that case, there's no need for me to interfere. You'll attempt the descent of an angel out of desperation.","TWN":"既然如此，即使我不插手，走投無路的你們也會嘗試召喚天使降臨。"},"stage":{"bg":"WAREHOUSE_03","bgm":"THEMA_CA_SWAN_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그 결과가 어떻게 될지는 모르겠지만…….","JPN":"その結果がどのような形になるかはわかりませんが……","ENG":"What happens next, though... is anyone's guess...","TWN":"結果會怎樣我不知道……"},"stage":{"bg":"WAREHOUSE_03","bgm":"THEMA_CA_SWAN_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"기꺼이 칭찬해드리죠, 카일 웡 소령.","JPN":"褒めてさしあげます、カイル・ウォン少佐。","ENG":"Allow me to offer you some well-earned praise, Major Kyle Wong.","TWN":"我非常欣賞你，凱爾少校。"},"stage":{"bg":"WAREHOUSE_03","bgm":"THEMA_CA_SWAN_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_PRIDE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L15_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"이 세계에서 당신은 스스로의 <color=#ffd34c>역할</color>을 충분히 완수하였습니다.","JPN":"この世界であなたは、ご自身の<color=#ffd34c>役</color>を十分果たしました。","ENG":"In this world, you've fulfilled your <color=#ffd34c>role</color> to the fullest.","TWN":"在這個世界，你已經充分扮演了自己的<color=#ffd34c>角色</color>。"},"stage":{"bg":"WAREHOUSE_03","bgm":"THEMA_CA_SWAN_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그럼, 이만 조속히 무대에서 퇴장하시길.","JPN":"それでは、ただちに舞台から退場してもらいましょう。","ENG":"Now then... it's time you made your swift exit from the stage.","TWN":"現在可以退場了。"},"stage":{"bg":"WAREHOUSE_03","bgm":"THEMA_CA_SWAN_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}}]`);export{e as default};